   387→            if (updatedNotes[id]) {
   388→              updatedNotes[id] = {
   389→                ...updatedNotes[id],
   390→                isArchived: true,
   391→                updatedAt: new Date(),
   392→              };
   393→            }
   394→          });
   395→          return { notes: updatedNotes };
   396→        });
   397→        log.debug('Archived notes', { count: noteIds.length });
   398→      },
   399→
   400→      unarchiveNotes: (noteIds) => {
   401→        set((state) => {
   402→          const updatedNotes = { ...state.notes };
   403→          noteIds.forEach((id) => {
   404→            if (updatedNotes[id]) {
   405→              updatedNotes[id] = {
   406→                ...updatedNotes[id],
   407→                isArchived: false,
   408→                updatedAt: new Date(),
   409→              };
   410→            }
   411→          });
   412→          return { notes: updatedNotes };
   413→        });
   414→        log.debug('Unarchived notes', { count: noteIds.length });
   415→      },
   416→
   417→      // Queries
   418→      getAllNotes: () => {
   419→        const state = get();
   420→        const notes = Object.values(state.notes);
   421→        const filtered = filterNotes(notes, state.filter);
   422→        return sortNotes(filtered, state.sortConfig);
   423→      },
   424→
   425→      getNotesByFolder: (folderId) => {
   426→        const state = get();
   427→        const notes = Object.values(state.notes).filter(
   428→          (note) => note.folderId === folderId
   429→        );
   430→        const filtered = filterNotes(notes, state.filter);
   431→        return sortNotes(filtered, state.sortConfig);
   432→      },
   433→
   434→      getNotesBy: (predicate) => {
   435→        const notes = Object.values(get().notes).filter(predicate);
   436→        return sortNotes(notes, get().sortConfig);
   437→      },
   438→
   439→      searchNotes: (query) => {
   440→        if (!query.trim()) return [];
   441→
   442→        const lowerQuery = query.toLowerCase();
   443→        const notes = Object.values(get().notes).filter((note) => {
   444→          // Search in title, content text, and tags
   445→          return (
   446→            note.title.toLowerCase().includes(lowerQuery) ||
   447→            note.contentText.toLowerCase().includes(lowerQuery) ||
   448→            note.tags.some((tag) => tag.toLowerCase().includes(lowerQuery))
   449→          );
   450→        });
   451→
   452→        return sortNotes(notes, get().sortConfig);
   453→      },
   454→
   455→      // Pin/Archive
   456→      togglePin: (id) => {
   457→        const note = get().notes[id];
   458→        if (!note) return;
   459→
   460→        set((state) => ({
   461→          notes: {
   462→            ...state.notes,
   463→            [id]: {
   464→              ...note,
   465→              isPinned: !note.isPinned,
   466→              updatedAt: new Date(),
   467→            },
   468→          },
   469→        }));
   470→        log.debug('Toggled pin', { id, isPinned: !note.isPinned });
   471→      },
   472→
   473→      toggleArchive: (id) => {
   474→        const note = get().notes[id];
   475→        if (!note) return;
   476→
   477→        set((state) => ({
   478→          notes: {
   479→            ...state.notes,
   480→            [id]: {
   481→              ...note,
   482→              isArchived: !note.isArchived,
   483→              updatedAt: new Date(),
   484→            },
   485→          },
   486→        }));
   487→        log.debug('Toggled archive', { id, isArchived: !note.isArchived });
   488→      },
   489→
   490→      toggleFavorite: (id) => {
   491→        const note = get().notes[id];
   492→        if (!note) return;
   493→
   494→        set((state) => ({
   495→          notes: {
   496→            ...state.notes,
   497→            [id]: {
   498→              ...note,
   499→              isFavorite: !note.isFavorite,
   500→              updatedAt: new Date(),
   501→            },
   502→          },
   503→        }));
   504→        log.debug('Toggled favorite', { id, isFavorite: !note.isFavorite });
   505→      },
   506→
   507→      // Tags
   508→      addTag: (id, tag) => {
   509→        const note = get().notes[id];
   510→        if (!note) return;
   511→
   512→        // Don't add duplicate tags
   513→        if (note.tags.includes(tag)) return;
   514→
   515→        // Check max tags limit
   516→        if (note.tags.length >= NOTE_CONSTANTS.MAX_TAGS) {
   517→          log.warn('Max tags reached', { max: NOTE_CONSTANTS.MAX_TAGS });
   518→          return;
   519→        }
   520→
   521→        set((state) => ({
   522→          notes: {
   523→            ...state.notes,
   524→            [id]: {
   525→              ...note,
   526→              tags: [...note.tags, tag],
   527→              updatedAt: new Date(),
   528→            },
   529→          },
   530→        }));
   531→        log.debug('Added tag', { id, tag });
   532→      },
   533→
   534→      removeTag: (id, tag) => {
   535→        const note = get().notes[id];
   536→        if (!note) return;
   537→
   538→        set((state) => ({
   539→          notes: {
   540→            ...state.notes,
   541→            [id]: {
   542→              ...note,
   543→              tags: note.tags.filter((t) => t !== tag),
   544→              updatedAt: new Date(),
   545→            },
   546→          },
   547→        }));
   548→        log.debug('Removed tag', { id, tag });
   549→      },
   550→
   551→      getAllTags: () => {
   552→        const notes = Object.values(get().notes);
   553→        const tagSet = new Set<string>();
   554→        notes.forEach((note) => {
   555→          note.tags.forEach((tag) => tagSet.add(tag));
   556→        });
   557→        return Array.from(tagSet).sort();
   558→      },
   559→
   560→      // UI state
   561→      setActiveNote: (id) => {
   562→        set({ activeNoteId: id });
   563→        log.debug('Active note set', { id });
   564→      },
   565→
   566→      setSortConfig: (config) => {
   567→        set({ sortConfig: config });
   568→        log.debug('Sort config updated', { config });
   569→      },
   570→
   571→      setFilter: (filter) => {
   572→        set({ filter });
   573→        log.debug('Filter updated', { filter });
   574→      },
   575→
   576→      // Utility
   577→      getNoteCount: () => {
   578→        return Object.keys(get().notes).length;
   579→      },
   580→
   581→      getNotesInFolder: (folderId) => {
   582→        return Object.values(get().notes).filter(
   583→          (note) => note.folderId === folderId
   584→        );
   585→      },
   586→
   587→      exportNotes: () => {
   588→        return Object.values(get().notes);
   589→      },
   590→
   591→      importNotes: (notes, merge) => {
   592→        if (!merge) {
   593→          // Replace all notes
   594→          set({
   595→            notes: Object.fromEntries(notes.map((note) => [note.id, note])),
   596→            activeNoteId: null,
   597→          });
   598→          log.info('Imported notes', { count: notes.length, mode: 'replace' });
   599→        } else {
   600→          // Merge with existing notes
   601→          set((state) => {
   602→            const updatedNotes = { ...state.notes };
   603→            notes.forEach((note) => {
   604→              updatedNotes[note.id] = note;
   605→            });
   606→            return { notes: updatedNotes };
   607→          });
   608→          log.info('Imported notes', { count: notes.length, mode: 'merge' });
   609→        }
   610→      },
   611→
   612→      clearAllNotes: () => {
   613→        set({ notes: {}, activeNoteId: null });
   614→        log.info('All notes cleared');
   615→      },
   616→
   617→      // ==================== BACKLINKS (Phase 4) ====================
   618→
   619→      getBacklinks: (noteId: string) => {
   620→        const state = get();
   621→        const note = state.notes[noteId];
   622→        if (!note) return [];
   623→
   624→        return getBacklinksUtil(noteId, note.title, state.notes);
   625→      },
   626→
   627→      updateLinkedNotes: (noteId: string, content: string) => {
   628→        const state = get();
   629→        const linkTitles = extractWikiLinks(content);
   630→        const linkedNoteIds = resolveLinksToIds(linkTitles, state.notes);
   631→
   632→        set((currentState) => {
   633→          const note = currentState.notes[noteId];
   634→          if (!note) return currentState;
   635→
   636→          return {
   637→            notes: {
   638→              ...currentState.notes,
   639→              [noteId]: {
   640→                ...note,
   641→                linkedNotes: linkedNoteIds,
   642→              },
   643→            },
   644→          };
   645→        });
   646→      },
   647→
   648→      // ==================== TEMPLATES (Phase 4) ====================
   649→
   650→      getNoteTemplates: () => {
   651→        return DEFAULT_NOTE_TEMPLATES;
   652→      },
   653→
   654→      createNoteFromTemplate: (templateId: string) => {
   655→        const template = DEFAULT_NOTE_TEMPLATES.find((t) => t.id === templateId);
   656→        if (!template) return null;
   657→
   658→        const newNote = createDefaultNote({
   659→          title: template.name,
   660→          contentText: template.description,
   661→          tags: template.defaultTags || [],
   662→          icon: template.icon,
   663→        });
   664→
   665→        set((state) => ({
   666→          notes: {
   667→            ...state.notes,
   668→            [newNote.id]: newNote,
   669→          },
   670→          activeNoteId: newNote.id,
   671→        }));
   672→
   673→        log.debug('Created note from template', { template: template.name });
   674→        return newNote;
   675→      },
   676→    }),
   677→    {
   678→      name: 'notes', // IndexedDB key
   679→      storage: createJSONStorage(() => createSyncedStorage()),
   680→      partialize: (state) => ({
   681→        // Only persist notes, not UI state
   682→        notes: state.notes,
   683→      }),
   684→      // Handle date serialization
   685→      onRehydrateStorage: () => (state) => {
   686→        log.debug('Notes store rehydrating');
   687→        if (state) {
   688→          try {
   689→            // Ensure notes object exists and is valid
   690→            if (state.notes && typeof state.notes === 'object') {
   691→              // Convert date strings back to Date objects
   692→              Object.values(state.notes).forEach((note) => {
   693→                if (typeof note.createdAt === 'string') {
   694→                  note.createdAt = new Date(note.createdAt);
   695→                }
   696→                if (typeof note.updatedAt === 'string') {
   697→                  note.updatedAt = new Date(note.updatedAt);
   698→                }
   699→              });
   700→            } else {
   701→              log.warn('Corrupted notes data detected, resetting to empty');
   702→              state.notes = {};
   703→            }
   704→          } catch (err) {
   705→            log.error('Error during notes store rehydration', { error: err });
   706→            // Reset to safe defaults
   707→            state.notes = {};
   708→            state.activeNoteId = null;
   709→          }
   710→        }
   711→        log.info('Notes store rehydrated');
   712→      },
   713→    }
   714→  )
   715→);
   716→
   717→/**
   718→ * Selector hooks for optimized re-renders
   719→ */
   720→export const useActiveNote = () =>
   721→  useNotesStore((state) => {
   722→    const activeId = state.activeNoteId;
   723→    return activeId ? state.notes[activeId] : null;
   724→  });
   725→
   726→export const useNotesByFolder = (folderId: string | null) =>
   727→  useNotesStore((state) => state.getNotesByFolder(folderId));
