   374→            return { ...task, status: columns[0].id as TaskStatus };
   375→          }
   376→
   377→          // Try exact match first (case-insensitive)
   378→          let newColumn = columns.find(c =>
   379→            c.title.toLowerCase() === oldColumn.title.toLowerCase()
   380→          );
   381→
   382→          // If no exact match, try partial match (contains)
   383→          if (!newColumn) {
   384→            newColumn = columns.find(c =>
   385→              c.title.toLowerCase().includes(oldColumn.title.toLowerCase()) ||
   386→              oldColumn.title.toLowerCase().includes(c.title.toLowerCase())
   387→            );
   388→          }
   389→
   390→          // Fallback: first column
