   392→            newColumn = columns[0];
   393→          }
   394→
   395→          return { ...task, status: newColumn.id as TaskStatus };
   396→        });
   397→
   398→        set({ columns, tasks });
   399→      },
   400→
   401→      // ==================== CHECKLIST ACTIONS ====================
   402→
   403→      addChecklistItem: (taskId, text) => {
   404→        const task = get().tasks.find((t) => t.id === taskId);
   405→        if (!task) return;
   406→
   407→        const newItem: ChecklistItem = {
   408→          id: `check-${Date.now()}`,
   409→          text,
   410→          completed: false,
   411→          order: (task.checklist || []).length,
   412→          createdAt: new Date().toISOString(),
   413→        };
   414→
   415→        set((state) => ({
   416→          tasks: state.tasks.map((t) =>
   417→            t.id === taskId
   418→              ? { ...t, checklist: [...(t.checklist || []), newItem] }
   419→              : t
   420→          ),
   421→        }));
   422→
   423→        // Log checklist update
   424→        get().logActivity(taskId, {
   425→          action: 'checklist_updated',
   426→          newValue: `Added: ${text}`,
   427→        });
   428→      },
   429→
   430→      updateChecklistItem: (taskId, itemId, updates) => {
   431→        set((state) => ({
   432→          tasks: state.tasks.map((t) =>
   433→            t.id === taskId
   434→              ? {
   435→                  ...t,
   436→                  checklist: (t.checklist || []).map((item) =>
   437→                    item.id === itemId ? { ...item, ...updates } : item
   438→                  ),
   439→                }
   440→              : t
   441→          ),
   442→        }));
   443→      },
   444→
   445→      deleteChecklistItem: (taskId, itemId) => {
   446→        const task = get().tasks.find((t) => t.id === taskId);
   447→        if (!task) return;
   448→
   449→        const item = task.checklist?.find((i) => i.id === itemId);
   450→        if (!item) return;
