  1014→      autoArchiveCompletedTasks: () => {
  1015→        const now = new Date();
  1016→        const fourteenDaysAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);
  1017→
  1018→        const tasksToArchive = get().tasks.filter((task) => {
  1019→          // Only archive tasks in "done" status
