  1080→
  1081→        const startTime = new Date(task.timeTracking.activeTimerStart);
  1082→        const endTime = new Date(now);
  1083→        const duration = Math.floor((endTime.getTime() - startTime.getTime()) / 1000); // seconds
  1084→
  1085→        set((state) => ({
  1086→          tasks: state.tasks.map((t) => {
  1087→            if (t.id === taskId && t.timeTracking) {
  1088→              const newEntry = {
