### 5. **Migration Patterns for Schema Changes**

**Real example:** `useCalendarStore` has a one-time migration function:

```typescript
// In useCalendarStore.ts
function migrateLegacyDateKeys(events: Record<string, CalendarEvent[]>) {
  const migratedEvents: Record<string, CalendarEvent[]> = {};
  let migrationCount = 0;

  for (const [oldKey, eventList] of Object.entries(events)) {
    // Convert old format "2025-0-15" to new "2025-1-15"
    const parts = oldKey.split('-');
    const year = parseInt(parts[0], 10);
    const month = parseInt(parts[1], 10);
    const day = parseInt(parts[2], 10);

    const isLikelyLegacyKey = month >= 0 && month <= 11;
    if (isLikelyLegacyKey) {
      const date = new Date(year, month, day);
      const newKey = getStandardDateKey(date);
      if (oldKey !== newKey) {
        migratedEvents[newKey] = eventList;
        migrationCount++;
      }
    }
  }

  return migratedEvents;
}

// Run migration on app load
export const useCalendarStore = create<CalendarStore>()(
  persist(
    // ... store definition
    {
      name: 'calendar-events',
      storage: createJSONStorage(() => createSyncedStorage()),
      onRehydrateStorage: () => (state) => {
        if (state && state.events) {
          state.events = migrateLegacyDateKeys(state.events);
        }
      },
    }
  )
);
```

**Migration strategy:**
- Detect old vs new format
- Transform data before rehydration
- Log migration count
- Transparent to user

---

### 6. **Store-Specific Patterns**

#### **useKanbanStore** (tasks)
```typescript
persist(
  (set, get) => ({ /* actions */ }),
  {
    name: 'kanban-tasks',
    storage: createJSONStorage(() => createSyncedStorage()),
    // No partialize - persists entire state
  }
)
```

#### **useNotesStore** (selective persistence)
```typescript
persist(
  (set, get) => ({ /* actions */ }),
  {
    name: 'notes',
    storage: createJSONStorage(() => createSyncedStorage()),
    partialize: (state) => ({
      notes: state.notes,  // Only persist notes data
      // NOT activeNoteId, sortConfig, filter (UI state)
    }),
    onRehydrateStorage: () => (state) => {
      if (state?.notes) {
        // Convert date strings to Date objects
        Object.values(state.notes).forEach((note) => {
          if (typeof note.createdAt === 'string') {
            note.createdAt = new Date(note.createdAt);
          }
          if (typeof note.updatedAt === 'string') {
            note.updatedAt = new Date(note.updatedAt);
          }
        });
      }
    },
  }
)
```

#### **useCalendarStore** (date serialization + migration)
```typescript
persist(
  (set, get) => ({ /* actions */ }),
  {
    name: 'calendar-events',
    storage: createJSONStorage(() => createSyncedStorage()),
    partialize: (state) => ({
      events: state.events,
      viewMode: state.viewMode,
      // NOT currentDate (can be recalculated)
    }),
    onRehydrateStorage: () => (state) => {
      if (state?.events) {
        state.events = migrateLegacyDateKeys(state.events);
      }
    },
  }
)
```

---

### 7. **Best Practices from Existing Code**

1. **Use `partialize` to exclude UI state** - Only persist data, not transient UI (active selection, view mode, sort config)

2. **Handle date serialization** - JSON doesn't preserve Date objects; convert on rehydration:
   ```typescript
   if (typeof note.createdAt === 'string') {
     note.createdAt = new Date(note.createdAt);
   }
   ```

3. **Log during rehydration** - Debug data corruption issues:
   ```typescript
   onRehydrateStorage: () => (state) => {
     log.debug('Store rehydrating');
     if (state) { /* transform data */ }
     log.info('Store rehydrated');
   }
   ```

4. **Validate on load** - Catch corrupted data:
   ```typescript
   if (state.notes && typeof state.notes === 'object') {
     // Valid - proceed
   } else {
     log.warn('Corrupted data, resetting');
     state.notes = {};
   }
   ```

5. **Use activity logging** - Track state changes for audit trails (see `useKanbanStore.logActivity`)

6. **Batch operations for performance** - Use `setItemsBatch()` for multiple items (50-100x faster)

7. **Show save status** - `saveStatusActions.setSaving()` / `setSaved()` for UX feedback

---

### 8. **For useBookmarkStore - Recommended Pattern**

```typescript
import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';
import { createSyncedStorage } from '../lib/syncedStorage';
import { logger } from '../services/logger';

const log = logger.module('BookmarkStore');

interface Bookmark {
  id: string;
  url: string;
  title: string;
  description?: string;
  tags: string[];
  favicon?: string;
  createdAt: Date;
  updatedAt: Date;
  isArchived: boolean;
}

interface BookmarkStore {
  bookmarks: Record<string, Bookmark>;
  activeTagFilter: string | null;

  // CRUD
  addBookmark: (data: Omit<Bookmark, 'id' | 'createdAt' | 'updatedAt'>) => Bookmark;
  updateBookmark: (id: string, updates: Partial<Bookmark>) => void;
  deleteBookmark: (id: string) => void;

  // Queries
  getBookmark: (id: string) => Bookmark | undefined;
  getAllBookmarks: () => Bookmark[];
  getBookmarksByTag: (tag: string) => Bookmark[];
  searchBookmarks: (query: string) => Bookmark[];

  // Bulk
  deleteBookmarks: (ids: string[]) => void;
  addTags: (id: string, tags: string[]) => void;
  removeTags: (id: string, tags: string[]) => void;
}

export const useBookmarkStore = create<BookmarkStore>()(
  persist(
    (set, get) => ({
      bookmarks: {},
      activeTagFilter: null,

      addBookmark: (data) => {
        const id = Date.now().toString();
        const bookmark: Bookmark = {
          ...data,
          id,
          createdAt: new Date(),
          updatedAt: new Date(),
        };

        set((state) => ({
          bookmarks: { ...state.bookmarks, [id]: bookmark },
        }));

        log.debug('Bookmark created', { id, url: data.url });
        return bookmark;
      },

      // ... other actions
    }),
    {
      name: 'bookmarks', // IndexedDB key
      storage: createJSONStorage(() => createSyncedStorage()),
      partialize: (state) => ({
        bookmarks: state.bookmarks, // Only persist data
      }),
      onRehydrateStorage: () => (state) => {
        log.debug('Bookmarks store rehydrating');
        if (state?.bookmarks) {
          try {
            Object.values(state.bookmarks).forEach((bookmark) => {
              if (typeof bookmark.createdAt === 'string') {
                bookmark.createdAt = new Date(bookmark.createdAt);
              }
              if (typeof bookmark.updatedAt === 'string') {
                bookmark.updatedAt = new Date(bookmark.updatedAt);
              }
            });
          } catch (err) {
            log.error('Corruption detected', { error: err });
            state.bookmarks = {};
          }
        }
        log.info('Bookmarks store rehydrated');
      },
    }
  )
);
```

